INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00240', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在漫步時我的腦中並非一片空白，它有時喚起童年抬便當聞到的氣味： 那是班上五十個孩子便當混在一起的氣味，……如果仔細回想，就知道一 張在街頭獲得的照片不會只是按快門的一瞬，它是一段插敘不斷的敘事， 一張照片喚起的可能是人類獨有的，涉及自我覺知與複雜經驗的記憶形 式。」假設以上文字是美術館某項展覽的文案，下列何者最適合？', '["版印年畫特展", "畫說保存維護特展", "台糖百年蔗糖影像展", "人體素描與石膏雕塑展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00241', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「成功，其實可以很簡單！不是看職位高低、財富多少；而是心中有夢想、 手中有做法。歐洲理財大師博多・雪佛對成功提出一個與眾不同的定義， 他說：『成功，是按照自己所建構的生活藍圖，去操控自己的生活。』不 論現在的成就如何，只要能夠認清自己的目標，誠懇地接受自己目前的處 境，對其中有些需要改進的地方全力以赴，願意繼續認真地向前走，這個 過程就是成功。」根據上文，下列選項何者錯誤？', '["職位的高低與財富多少，不能定義何謂成功", "能主導公司發展的方向並掌握資源，才能獲得成功", "成功就是依照自己所擘劃的藍圖，讓自己能操控生活", "成功不看目前的成就，而是能認清目標與處境並持續的努力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00242', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「人的覺悟常是心上剎那間事。能忽然發現到井口的天光，發現自己是井 底的人兒，已是偶然了，如何爬上去就更艱難。」下列選項，何者最貼合 上文的旨意？', '["井底之蛙視野有限，要超越侷限處處碰壁", "天光猶如理想的召喚，但要達成心願很艱難", "人若不知自我反省，要成就一番事業便困難重重", "人就算察覺自己的不足，真要有所成長談何容易"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00243', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「真奈排在等待快車的人龍後面，從口袋裡掏出口罩遮住臉。定睛一看， 周圍的人十有八九都戴著口罩，不分男女老少。大概是為了預防流感和花 粉症吧，但是冷靜想想，還真是匪夷所思的光景。一大群戴著口罩的人全 都低著頭，把玩手裡的手機。剛來東京念專門學校時，真奈真的很討厭擠 滿人的電車，難以相信每天上學都必須與陌生人緊貼身體。所以都會的人 才會在不知不覺間這麼依賴口罩，不只是為了預防病毒或花粉，也是為了 保護自己。痛恨與陌生人緊貼身體，卻又目不轉睛地關注著就連在哪兒都 不知道的陌生人的『自言自語』。這輛電車上恐怕有一半以上的乘客都在 做跟自己相同的事。仔細想想，果然是不太正常的光景。」下列選項，何 者最可能是上述短文中所提到的「自言自語」？', '["低頭看手機上的文章，並低聲唸出", "好奇心旺盛，很想知道別人在自言自語什麼", "依賴社群軟體，無時無刻盯著網路上他人的訊息", "因怕被傳染而戴上口罩，無法和人交談，只能自言自語"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00244', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「據說秦始皇有一次想把他的苑囿擴大，大得東到函谷關，西到今天的鳳 翔和寶鷄。宮中的弄臣優旃說：『妙極了！多放些動物在裏面吧。要是敵 人從東邊打過來，只要教糜鹿用角去抵抗，就夠了。』秦始皇聽了，就把 這計畫擱了下來。這麼看來，幽默實在是荒謬的解藥。委婉的幽默，往往 順著荒謬的邏輯誇張下去，使人領悟荒謬的後果。幽默並不等於尖刻，因 為幽默針對的不是荒謬的人，而是荒謬本身。真正幽默的心靈，絕不抱定 一個角度去看人或看自己，他不但會幽默人，也會幽默自己，不但嘲笑人， 也會釋然自嘲，泰然自貶。」根據上文，秦始皇擱置計畫最可能的原因是：', '["苑囿過大容易引起敵人覬覦田獵之利", "瞭解光靠訓練糜鹿無法遏阻強敵入侵", "苑中動物會妨礙軍事訓練，不利抗敵", "擴建苑囿恐勞民傷財，不能克敵致勝"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00245', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，下列對於「幽默」的詮釋，最適合的是：', '["真正具幽默感的人往往善於自我嘲弄與自我貶抑", "幽默與荒謬並存，幽默的心靈亦有其荒謬的一面", "幽默可降低言語的殺傷力，使荒謬之感獲得淡化", "將荒謬的邏輯加以誇張，尖刻與幽默皆獲得強化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00246', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「這樣不推銷的推銷術，在這裡最合適。有些店舖，主顧上門，不但不著 急兜攬生意，而且於客氣之中寓有生疏之意。例如書店，進得店門，四壁 圖書雖然塞得滿滿的，但盡是些普通書籍，你若問他有什麼好書，他說沒 有什麼，你說隨便看看，他說請看請看。結果是你什麼好書也看不見，但 是你若去過幾次，做成幾回生意，情形就不同了，他會請你到裡櫃坐，再 過些時請到後櫃坐，升堂入室之後，箱子裡的好書善本陸陸續續的都拿出 來了。宋版的，元槧的，琳琅滿目，還小聲的囑咐你，不要對外人說，生 意之外，還套著交情。」下列選項，何者最能形容文中的推銷術？', '["深藏若虛", "虛懷若谷", "明褒暗貶", "循循善誘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00247', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「總是嚮往一處可以憩息的地方，好讓你卸下肩頭的重擔，有人叫著你的 名字，像百年榕樹永遠認得飄零的葉子。啊，家的感覺或許很簡單，不管 飄盪多少年，衣衫如何襤褸，老宅旁邊榕蔭下，有一塊石墩讓你小坐，下 弈的老人數算將士兵馬，還不忘告訴你，這兒有冰鎮的麥茶。沒有人攻訐 你的過往，古井流水依然清澈，你可以洗癒炎涼江湖烙在身上的傷疤，你 無需在惡意的詆毀中像奔逃的小鹿，亦不必沈溺於浮名如迷途的羔羊，你 只是一個願意關愛他人也被呵護著的人，你是春雀的同伴，流雲的知己。 月亮照耀青窗，窗裡窗外皆有青色的光。不管遠方如何聲討你是背信的人， 月光下總有一扇青窗，堅持說你是唯一被等待的人。」根據上文，下列選 項何者最符合作者意旨？', '["人生如逆旅，我們不斷飄盪在這處那處之間", "家鄉永遠只存留在模糊的記憶之中供人憑弔", "純樸而溫厚的鄉村是旅遊與休閒的最佳去處", "家鄉永遠敞開溫暖雙臂迎接漂泊的遊子歸來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00248', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「望著海洋一陣的強風帶給海面一大片的灰暗，景象帶來淒涼的落寂感， 洞裡的青煙使我想到拓拔斯（布農族）的小說《最後的獵人》裡的男主角 比雅日和妻子帕蘇拉的故事。帕蘇拉對比雅日說：『……如果你聽我的話 到平地做臨時綑工，買幾件毛衣就不需為冷天劈柴烤火取暖……。』但比 雅日終究沒有去平地做綑工，反而上山去打獵；因為只有在深山才覺得有 尊嚴，有智慧，真正展露布農男人的氣魄。雖然在回部落途中他的獵物被 檢查哨的惡警擄走，僅留給他一隻狐狸孝敬帕蘇拉。比雅日無膽怨嘆，只 覺得惡質剝削在越為複雜的社會裡如鬼魂般地經常的，自然的落在弱勢、 窮人的命運裡。」下列選項，最符合本文旨意的是：', '["以客觀的角度分析原住民族文化在現實社會中的優勢與劣勢", "即使生活受到壓迫，仍無法取代原住民族對自身文化的熱愛", "認為原住民族文化是其唯一的依歸，只有與外界阻隔才能保留", "作者對於原住民族文化的關懷，盼望政府能給予原住民族工作機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00249', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '繪本《活了一百萬次的貓》作者佐野洋子面對癌轉移的任性態度，堪稱經 典。洋子只問醫師兩個問題：「還有幾年？」「到死之前要花多少錢？」 確定錢都夠花，立刻決定：「請不要延長我的壽命。」然後在回家路上， 走進名車代理店，指著英格蘭綠的積架說：「買了。」「得知還有兩年可 活，折磨了我數十年的憂鬱症也好了！」她說知道自己的死期，也得到了 自由。佐野洋子真是神奇歐巴桑。看來，自知死之將至，也沒什麼不好， 重要的是我們能不能有足夠的自由，選擇走到生命末日的方式。根據上文， 下列選項最接近作者人生旨趣的是：', '["反對佐野洋子癌症轉移後放棄治療", "人自知死亡之將至有益治療憂鬱症", "只要財力足夠就可以安享生命末期", "人即使到生命末期也要能自主安頓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
